chart-avg-tokens-per-message.query:
fetch spans
| filter service.name == "openclaw-gateway" AND span.name == "openclaw.model.usage"
| summarize avg_total = avg(toLong(openclaw.tokens.total)), avg_output = avg(toLong(openclaw.tokens.output)), by: {openclaw.channel}

chart-messages-over-time.query:
fetch spans
| filter service.name == "openclaw-gateway" AND span.name == "openclaw.message.processed"
| makeTimeseries messages = count(), by: {openclaw.channel}

chart-model-latency-over-time.query:
fetch spans
| filter service.name == "openclaw-gateway" AND span.name == "openclaw.model.usage"
| makeTimeseries avg_latency = avg(toDouble(duration) / 1000000000.0), by: {openclaw.model}

chart-output-tokens-over-time.query:
fetch spans
| filter service.name == "openclaw-gateway" AND span.name == "openclaw.model.usage"
| makeTimeseries output_tokens = sum(toLong(openclaw.tokens.output)), by: {openclaw.channel}

chart-p95-response-time.query:
fetch spans
| filter service.name == "openclaw-gateway" AND span.name == "openclaw.message.processed"
| summarize p95_duration = percentile(toDouble(duration) / 1000000000.0, 95), by: {openclaw.channel}

chart-response-time-by-channel.query:
fetch spans
| filter service.name == "openclaw-gateway" AND span.name == "openclaw.message.processed"
| summarize avg_duration = avg(toDouble(duration) / 1000000000.0), by: {openclaw.channel}
